const input = $input.first().json;
const action = input.action || 'list_posts';

const SUPABASE_URL = '{{SUPABASE_URL}}';
const SUPABASE_KEY = '{{SUPABASE_SERVICE_KEY}}';
const pgHeaders = { 'apikey': SUPABASE_KEY, 'Authorization': 'Bearer ' + SUPABASE_KEY };

const allCreds = await helpers.httpRequest({
  method: 'GET',
  url: SUPABASE_URL + '/rest/v1/template_credentials?template_id=eq.wordpress&select=cred_key,cred_value',
  headers: pgHeaders
});
const creds = {};
for (const c of (allCreds || [])) creds[c.cred_key] = c.cred_value;

if (!creds.wp_url || !creds.wp_username || !creds.wp_app_password) {
  return [{ json: { error: 'WordPress credentials missing. Use add_credential to set wp_url, wp_username, and wp_app_password.' } }];
}

const baseUrl = creds.wp_url.replace(/\/+$/, '');
const apiBase = baseUrl + '/wp-json/wp/v2';
const authHeader = 'Basic ' + Buffer.from(creds.wp_username + ':' + creds.wp_app_password).toString('base64');
const wpHeaders = { 'Authorization': authHeader, 'Content-Type': 'application/json' };

function stripHtml(html) {
  if (!html) return '';
  return String(html).replace(/<[^>]*>/g, '').replace(/&nbsp;/g, ' ').replace(/&amp;/g, '&').replace(/&lt;/g, '<').replace(/&gt;/g, '>').replace(/&quot;/g, '"').replace(/&#8217;/g, "'").replace(/&#8220;|&#8221;/g, '"').trim();
}

function truncate(s, n) {
  if (!s) return '';
  s = String(s);
  return s.length > n ? s.substring(0, n) + '...' : s;
}

function titleOf(p) {
  return (p.title && p.title.rendered) ? p.title.rendered : (p.title || '(no title)');
}

function formatItem(p) {
  const title = titleOf(p);
  const excerpt = p.excerpt && p.excerpt.rendered ? stripHtml(p.excerpt.rendered) : '';
  let s = 'ID ' + p.id + ' — "' + title + '" [' + p.status + ']';
  if (excerpt) s += '\n  ' + truncate(excerpt, 150);
  if (p.link) s += '\n  ' + p.link;
  return s;
}

function parseIdList(v) {
  if (v === undefined || v === null || v === '') return undefined;
  return String(v).split(',').map(s => parseInt(s.trim())).filter(n => !isNaN(n));
}

// ─────────────────────────────── list_posts ───────────────────────────────
if (action === 'list_posts') {
  const perPage = Math.min(parseInt(input.per_page) || 10, 100);
  const params = new URLSearchParams();
  params.append('per_page', String(perPage));
  if (input.search) params.append('search', input.search);
  if (input.status) params.append('status', input.status);
  if (input.page) params.append('page', String(input.page));
  try {
    const data = await helpers.httpRequest({ method: 'GET', url: apiBase + '/posts?' + params.toString(), headers: wpHeaders });
    if (!data || data.length === 0) return [{ json: { result: 'No posts found.' } }];
    let result = 'Found ' + data.length + ' posts:\n\n';
    for (const p of data) result += formatItem(p) + '\n\n';
    return [{ json: { result: result.trim() } }];
  } catch (err) {
    return [{ json: { error: 'Failed to list posts: ' + err.message } }];
  }

// ─────────────────────────────── get_post ───────────────────────────────
} else if (action === 'get_post') {
  const id = input.id;
  if (!id) return [{ json: { error: 'Parameter "id" is required (e.g. 1).' } }];
  try {
    const p = await helpers.httpRequest({ method: 'GET', url: apiBase + '/posts/' + encodeURIComponent(id), headers: wpHeaders });
    let result = '**' + titleOf(p) + '**\n';
    result += 'ID: ' + p.id + ' | Status: ' + p.status + ' | Date: ' + p.date + '\n';
    if (p.link) result += 'Link: ' + p.link + '\n';
    if (p.author) result += 'Author: ' + p.author + '\n';
    if (p.categories && p.categories.length) result += 'Categories: ' + p.categories.join(', ') + '\n';
    if (p.tags && p.tags.length) result += 'Tags: ' + p.tags.join(', ') + '\n';
    const content = p.content && p.content.rendered ? stripHtml(p.content.rendered) : '';
    result += '\nContent:\n' + content;
    if (result.length > 5000) result = result.substring(0, 5000) + '\n\n... (truncated, ' + result.length + ' chars total)';
    return [{ json: { result } }];
  } catch (err) {
    return [{ json: { error: 'Failed to get post: ' + err.message } }];
  }

// ─────────────────────────────── create_post ───────────────────────────────
} else if (action === 'create_post') {
  const title = input.title;
  if (!title) return [{ json: { error: 'Parameter "title" is required.' } }];
  const body = { title, status: input.status || 'draft' };
  if (input.content) body.content = input.content;
  if (input.excerpt) body.excerpt = input.excerpt;
  const cats = parseIdList(input.categories);
  if (cats && cats.length) body.categories = cats;
  const tags = parseIdList(input.tags);
  if (tags && tags.length) body.tags = tags;
  try {
    const p = await helpers.httpRequest({ method: 'POST', url: apiBase + '/posts', headers: wpHeaders, body: JSON.stringify(body) });
    return [{ json: { result: 'Post created: ID ' + p.id + ' — "' + titleOf(p) + '" [' + p.status + ']' + (p.link ? '\nLink: ' + p.link : '') } }];
  } catch (err) {
    return [{ json: { error: 'Failed to create post: ' + err.message } }];
  }

// ─────────────────────────────── update_post ───────────────────────────────
} else if (action === 'update_post') {
  const id = input.id;
  if (!id) return [{ json: { error: 'Parameter "id" is required.' } }];
  const body = {};
  if (input.title !== undefined && input.title !== '') body.title = input.title;
  if (input.content !== undefined && input.content !== '') body.content = input.content;
  if (input.status !== undefined && input.status !== '') body.status = input.status;
  if (input.excerpt !== undefined && input.excerpt !== '') body.excerpt = input.excerpt;
  const cats = parseIdList(input.categories);
  if (cats) body.categories = cats;
  const tags = parseIdList(input.tags);
  if (tags) body.tags = tags;
  if (Object.keys(body).length === 0) return [{ json: { error: 'At least one field (title, content, status, excerpt, categories, tags) is required.' } }];
  try {
    const p = await helpers.httpRequest({ method: 'POST', url: apiBase + '/posts/' + encodeURIComponent(id), headers: wpHeaders, body: JSON.stringify(body) });
    return [{ json: { result: 'Post updated: ID ' + p.id + ' — "' + titleOf(p) + '" [' + p.status + ']' } }];
  } catch (err) {
    return [{ json: { error: 'Failed to update post: ' + err.message } }];
  }

// ─────────────────────────────── delete_post ───────────────────────────────
} else if (action === 'delete_post') {
  const id = input.id;
  if (!id) return [{ json: { error: 'Parameter "id" is required.' } }];
  const force = input.force === true || input.force === 'true';
  try {
    await helpers.httpRequest({ method: 'DELETE', url: apiBase + '/posts/' + encodeURIComponent(id) + (force ? '?force=true' : ''), headers: wpHeaders });
    return [{ json: { result: force ? 'Post ' + id + ' permanently deleted.' : 'Post ' + id + ' moved to trash.' } }];
  } catch (err) {
    return [{ json: { error: 'Failed to delete post: ' + err.message } }];
  }

// ─────────────────────────────── list_pages ───────────────────────────────
} else if (action === 'list_pages') {
  const perPage = Math.min(parseInt(input.per_page) || 10, 100);
  const params = new URLSearchParams();
  params.append('per_page', String(perPage));
  if (input.search) params.append('search', input.search);
  if (input.status) params.append('status', input.status);
  try {
    const data = await helpers.httpRequest({ method: 'GET', url: apiBase + '/pages?' + params.toString(), headers: wpHeaders });
    if (!data || data.length === 0) return [{ json: { result: 'No pages found.' } }];
    let result = 'Found ' + data.length + ' pages:\n\n';
    for (const p of data) result += formatItem(p) + '\n\n';
    return [{ json: { result: result.trim() } }];
  } catch (err) {
    return [{ json: { error: 'Failed to list pages: ' + err.message } }];
  }

// ─────────────────────────────── get_page ───────────────────────────────
} else if (action === 'get_page') {
  const id = input.id;
  if (!id) return [{ json: { error: 'Parameter "id" is required.' } }];
  try {
    const p = await helpers.httpRequest({ method: 'GET', url: apiBase + '/pages/' + encodeURIComponent(id), headers: wpHeaders });
    let result = '**' + titleOf(p) + '**\n';
    result += 'ID: ' + p.id + ' | Status: ' + p.status + '\n';
    if (p.link) result += 'Link: ' + p.link + '\n';
    if (p.parent) result += 'Parent: ' + p.parent + '\n';
    const content = p.content && p.content.rendered ? stripHtml(p.content.rendered) : '';
    result += '\nContent:\n' + content;
    if (result.length > 5000) result = result.substring(0, 5000) + '\n\n... (truncated)';
    return [{ json: { result } }];
  } catch (err) {
    return [{ json: { error: 'Failed to get page: ' + err.message } }];
  }

// ─────────────────────────────── create_page ───────────────────────────────
} else if (action === 'create_page') {
  const title = input.title;
  if (!title) return [{ json: { error: 'Parameter "title" is required.' } }];
  const body = { title, status: input.status || 'draft' };
  if (input.content) body.content = input.content;
  if (input.parent) body.parent = parseInt(input.parent);
  try {
    const p = await helpers.httpRequest({ method: 'POST', url: apiBase + '/pages', headers: wpHeaders, body: JSON.stringify(body) });
    return [{ json: { result: 'Page created: ID ' + p.id + ' — "' + titleOf(p) + '" [' + p.status + ']' + (p.link ? '\nLink: ' + p.link : '') } }];
  } catch (err) {
    return [{ json: { error: 'Failed to create page: ' + err.message } }];
  }

// ─────────────────────────────── update_page ───────────────────────────────
} else if (action === 'update_page') {
  const id = input.id;
  if (!id) return [{ json: { error: 'Parameter "id" is required.' } }];
  const body = {};
  if (input.title !== undefined && input.title !== '') body.title = input.title;
  if (input.content !== undefined && input.content !== '') body.content = input.content;
  if (input.status !== undefined && input.status !== '') body.status = input.status;
  if (input.parent !== undefined && input.parent !== '') body.parent = parseInt(input.parent);
  if (Object.keys(body).length === 0) return [{ json: { error: 'At least one field to update is required.' } }];
  try {
    const p = await helpers.httpRequest({ method: 'POST', url: apiBase + '/pages/' + encodeURIComponent(id), headers: wpHeaders, body: JSON.stringify(body) });
    return [{ json: { result: 'Page updated: ID ' + p.id + ' — "' + titleOf(p) + '" [' + p.status + ']' } }];
  } catch (err) {
    return [{ json: { error: 'Failed to update page: ' + err.message } }];
  }

// ─────────────────────────────── delete_page ───────────────────────────────
} else if (action === 'delete_page') {
  const id = input.id;
  if (!id) return [{ json: { error: 'Parameter "id" is required.' } }];
  const force = input.force === true || input.force === 'true';
  try {
    await helpers.httpRequest({ method: 'DELETE', url: apiBase + '/pages/' + encodeURIComponent(id) + (force ? '?force=true' : ''), headers: wpHeaders });
    return [{ json: { result: force ? 'Page ' + id + ' permanently deleted.' : 'Page ' + id + ' moved to trash.' } }];
  } catch (err) {
    return [{ json: { error: 'Failed to delete page: ' + err.message } }];
  }

// ─────────────────────────────── list_comments ───────────────────────────────
} else if (action === 'list_comments') {
  const perPage = Math.min(parseInt(input.per_page) || 10, 100);
  const params = new URLSearchParams();
  params.append('per_page', String(perPage));
  if (input.post) params.append('post', String(input.post));
  if (input.status) params.append('status', input.status);
  try {
    const data = await helpers.httpRequest({ method: 'GET', url: apiBase + '/comments?' + params.toString(), headers: wpHeaders });
    if (!data || data.length === 0) return [{ json: { result: 'No comments found.' } }];
    let result = 'Found ' + data.length + ' comments:\n\n';
    for (const c of data) {
      const content = c.content && c.content.rendered ? stripHtml(c.content.rendered) : '';
      result += 'ID ' + c.id + ' [' + c.status + '] by "' + (c.author_name || '') + '" on post ' + c.post + '\n  ' + truncate(content, 200) + '\n\n';
    }
    return [{ json: { result: result.trim() } }];
  } catch (err) {
    return [{ json: { error: 'Failed to list comments: ' + err.message } }];
  }

// ─────────────────────────────── moderate_comment ───────────────────────────────
} else if (action === 'moderate_comment') {
  const id = input.id;
  const status = input.status;
  if (!id) return [{ json: { error: 'Parameter "id" is required.' } }];
  if (!status) return [{ json: { error: 'Parameter "status" is required. Use one of: approved, hold, spam, trash.' } }];
  const valid = ['approved', 'approve', 'hold', 'spam', 'trash'];
  if (!valid.includes(status)) return [{ json: { error: 'Invalid status "' + status + '". Use: approved, hold, spam, trash.' } }];
  const normalized = status === 'approve' ? 'approved' : status;
  try {
    const c = await helpers.httpRequest({ method: 'POST', url: apiBase + '/comments/' + encodeURIComponent(id), headers: wpHeaders, body: JSON.stringify({ status: normalized }) });
    return [{ json: { result: 'Comment ' + id + ' moderated: status = ' + c.status } }];
  } catch (err) {
    return [{ json: { error: 'Failed to moderate comment: ' + err.message } }];
  }

// ─────────────────────────────── list_categories ───────────────────────────────
} else if (action === 'list_categories') {
  const perPage = Math.min(parseInt(input.per_page) || 20, 100);
  const params = new URLSearchParams();
  params.append('per_page', String(perPage));
  if (input.search) params.append('search', input.search);
  try {
    const data = await helpers.httpRequest({ method: 'GET', url: apiBase + '/categories?' + params.toString(), headers: wpHeaders });
    if (!data || data.length === 0) return [{ json: { result: 'No categories found.' } }];
    let result = 'Found ' + data.length + ' categories:\n';
    for (const c of data) result += 'ID ' + c.id + ' — "' + c.name + '" (slug: ' + c.slug + ', ' + c.count + ' posts)\n';
    return [{ json: { result: result.trim() } }];
  } catch (err) {
    return [{ json: { error: 'Failed to list categories: ' + err.message } }];
  }

// ─────────────────────────────── create_category ───────────────────────────────
} else if (action === 'create_category') {
  const name = input.name;
  if (!name) return [{ json: { error: 'Parameter "name" is required.' } }];
  const body = { name };
  if (input.description) body.description = input.description;
  if (input.parent) body.parent = parseInt(input.parent);
  if (input.slug) body.slug = input.slug;
  try {
    const c = await helpers.httpRequest({ method: 'POST', url: apiBase + '/categories', headers: wpHeaders, body: JSON.stringify(body) });
    return [{ json: { result: 'Category created: ID ' + c.id + ' — "' + c.name + '" (slug: ' + c.slug + ')' } }];
  } catch (err) {
    return [{ json: { error: 'Failed to create category: ' + err.message } }];
  }

// ─────────────────────────────── list_tags ───────────────────────────────
} else if (action === 'list_tags') {
  const perPage = Math.min(parseInt(input.per_page) || 20, 100);
  const params = new URLSearchParams();
  params.append('per_page', String(perPage));
  if (input.search) params.append('search', input.search);
  try {
    const data = await helpers.httpRequest({ method: 'GET', url: apiBase + '/tags?' + params.toString(), headers: wpHeaders });
    if (!data || data.length === 0) return [{ json: { result: 'No tags found.' } }];
    let result = 'Found ' + data.length + ' tags:\n';
    for (const t of data) result += 'ID ' + t.id + ' — "' + t.name + '" (slug: ' + t.slug + ', ' + t.count + ' posts)\n';
    return [{ json: { result: result.trim() } }];
  } catch (err) {
    return [{ json: { error: 'Failed to list tags: ' + err.message } }];
  }

// ─────────────────────────────── list_users ───────────────────────────────
} else if (action === 'list_users') {
  const perPage = Math.min(parseInt(input.per_page) || 20, 100);
  const params = new URLSearchParams();
  params.append('per_page', String(perPage));
  try {
    const data = await helpers.httpRequest({ method: 'GET', url: apiBase + '/users?' + params.toString(), headers: wpHeaders });
    if (!data || data.length === 0) return [{ json: { result: 'No users found.' } }];
    let result = 'Found ' + data.length + ' users:\n';
    for (const u of data) result += 'ID ' + u.id + ' — "' + u.name + '" (@' + u.slug + ')\n';
    return [{ json: { result: result.trim() } }];
  } catch (err) {
    return [{ json: { error: 'Failed to list users: ' + err.message } }];
  }

// ─────────────────────────────── search ───────────────────────────────
} else if (action === 'search') {
  const query = input.query;
  if (!query) return [{ json: { error: 'Parameter "query" is required.' } }];
  const perPage = Math.min(parseInt(input.per_page) || 10, 100);
  const params = new URLSearchParams();
  params.append('search', query);
  params.append('per_page', String(perPage));
  if (input.type) params.append('type', input.type);
  try {
    const data = await helpers.httpRequest({ method: 'GET', url: apiBase + '/search?' + params.toString(), headers: wpHeaders });
    if (!data || data.length === 0) return [{ json: { result: 'No results for "' + query + '".' } }];
    let result = 'Found ' + data.length + ' results for "' + query + '":\n\n';
    for (const r of data) result += 'ID ' + r.id + ' [' + r.subtype + '] — "' + r.title + '"\n  ' + r.url + '\n\n';
    return [{ json: { result: result.trim() } }];
  } catch (err) {
    return [{ json: { error: 'Failed to search: ' + err.message } }];
  }

// ─────────────────────────────── list_media ───────────────────────────────
} else if (action === 'list_media') {
  const perPage = Math.min(parseInt(input.per_page) || 10, 100);
  const params = new URLSearchParams();
  params.append('per_page', String(perPage));
  if (input.search) params.append('search', input.search);
  if (input.media_type) params.append('media_type', input.media_type);
  try {
    const data = await helpers.httpRequest({ method: 'GET', url: apiBase + '/media?' + params.toString(), headers: wpHeaders });
    if (!data || data.length === 0) return [{ json: { result: 'No media found.' } }];
    let result = 'Found ' + data.length + ' media items:\n\n';
    for (const m of data) {
      const title = (m.title && m.title.rendered) || m.slug || '';
      result += 'ID ' + m.id + ' — "' + title + '" [' + m.mime_type + ']\n  ' + m.source_url + '\n\n';
    }
    return [{ json: { result: result.trim() } }];
  } catch (err) {
    return [{ json: { error: 'Failed to list media: ' + err.message } }];
  }

// ─────────────────────────────── upload_media ───────────────────────────────
} else if (action === 'upload_media') {
  if (!input.file_ref) return [{ json: { error: 'Parameter "file_ref" (File Bridge ID from a user-sent file, e.g. file-abc12345) is required.' } }];
  const BRIDGE_URL = 'http://file-bridge:3200';
  const form_fields = {};
  if (input.title) form_fields.title = input.title;
  if (input.alt_text) form_fields.alt_text = input.alt_text;
  if (input.caption) form_fields.caption = input.caption;
  try {
    const fwd = await helpers.httpRequest({
      method: 'POST',
      url: BRIDGE_URL + '/files/' + input.file_ref + '/forward',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        url: apiBase + '/media',
        headers: { 'Authorization': authHeader },
        form_fields: form_fields,
        filename: input.filename || undefined
      })
    });
    if (fwd && fwd.remote_status && fwd.remote_status >= 200 && fwd.remote_status < 300) {
      const media = fwd.remote_response || {};
      return [{ json: { result: 'Media uploaded: ID ' + (media.id || '?') + ' — ' + (media.source_url || '(no URL)') + (media.mime_type ? ' [' + media.mime_type + ']' : '') } }];
    }
    const errMsg = fwd && fwd.remote_response && fwd.remote_response.message ? fwd.remote_response.message : JSON.stringify(fwd);
    return [{ json: { error: 'Upload rejected by WordPress (HTTP ' + (fwd && fwd.remote_status) + '): ' + errMsg } }];
  } catch (err) {
    return [{ json: { error: 'Failed to upload media: ' + err.message } }];
  }

} else {
  return [{ json: { error: 'Unknown action: "' + action + '". Available: list_posts, get_post, create_post, update_post, delete_post, list_pages, get_page, create_page, update_page, delete_page, list_comments, moderate_comment, list_categories, create_category, list_tags, list_users, search, list_media, upload_media.' } }];
}
